 var results = source.TryGetNonEnumeratedCount(out int count)
     ? new List<int>(count)
     : new List<int>();
 foreach (var item in source)
     results.Add(Transform(item));
 ```

 **Impact: Avoids O(n) enumeration for counting; eliminates resizing allocations.**

